export const installOrgGithub = <ThrowOnError extends boolean = false>(options: Options<InstallOrgGithubData, ThrowOnError>): RequestResult<InstallOrgGithubResponses, InstallOrgGithubErrors, ThrowOnError> => (options.client ?? client).post<InstallOrgGithubResponses, InstallOrgGithubErrors, ThrowOnError>({ url: '/v1/orgs/{orgId}/integrations/github/install', ...options });

/**
 * Repositories the installed GitHub App can access (for display)
 */
export const listOrgGithubRepos = <ThrowOnError extends boolean = false>(options: Options<ListOrgGithubReposData, ThrowOnError>): RequestResult<ListOrgGithubReposResponses, ListOrgGithubReposErrors, ThrowOnError> => (options.client ?? client).get<ListOrgGithubReposResponses, ListOrgGithubReposErrors, ThrowOnError>({ url: '/v1/orgs/{orgId}/integrations/github/repos', ...options });

/**
 * A project's GitHub posting override
 */
export const getProjectGithubSettings = <ThrowOnError extends boolean = false>(options: Options<GetProjectGithubSettingsData, ThrowOnError>): RequestResult<GetProjectGithubSettingsResponses, GetProjectGithubSettingsErrors, ThrowOnError> => (options.client ?? client).get<GetProjectGithubSettingsResponses, GetProjectGithubSettingsErrors, ThrowOnError>({ url: '/v1/projects/{projectId}/integrations/github', ...options });

/**
 * Set a project's GitHub posting (mute / branch allow-list)
 */
export const updateProjectGithubSettings = <ThrowOnError extends boolean = false>(options: Options<UpdateProjectGithubSettingsData, ThrowOnError>): RequestResult<UpdateProjectGithubSettingsResponses, UpdateProjectGithubSettingsErrors, ThrowOnError> => (options.client ?? client).put<UpdateProjectGithubSettingsResponses, UpdateProjectGithubSettingsErrors, ThrowOnError>({
    url: '/v1/projects/{projectId}/integrations/github',
    ...options,
    headers: {
        'Content-Type': 'application/json',
        ...options.headers
    }
});
